#include <stdio.h>
#include <math.h>
typedef struct{double x,y,z;}V;
static V v(double x,double y,double z){V r={x,y,z};return r;}
static V add(V a,V b){return v(a.x+b.x,a.y+b.y,a.z+b.z);}
static V sub(V a,V b){return v(a.x-b.x,a.y-b.y,a.z-b.z);}
static V mul(V a,double s){return v(a.x*s,a.y*s,a.z*s);}
static double dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static V nrm(V a){return mul(a,1.0/sqrt(dot(a,a)));}

static V SC={0,-0.5,-5}; static double SR=1.0; static V L;

/* nearest sphere hit t>0.001, else -1 */
static double sphit(V o,V d){
  V oc=sub(o,SC);
  double a=dot(d,d),b=2*dot(d,oc),c=dot(oc,oc)-SR*SR;
  double disc=b*b-4*a*c;
  if(disc<0)return -1;
  double s=sqrt(disc);
  double t=(-b-s)/(2*a);
  if(t<=0.001)t=(-b+s)/(2*a);
  if(t<=0.001)return -1;
  return t;
}

static V trace(V o,V d){
  double ts=sphit(o,d);
  double tp=-1;
  if(fabs(d.y)>=1e-4){double t=(-1.5-o.y)/d.y; if(t>=0.001)tp=t;}
  int sph; V P,N;
  if(ts>0 && (tp<0 || ts<tp)){sph=1;P=add(o,mul(d,ts));N=nrm(sub(P,SC));}
  else if(tp>0){sph=0;P=add(o,mul(d,tp));N=v(0,1,0);}
  else{double t=0.5*(d.y+1.0);return add(mul(v(1,1,1),1-t),mul(v(0.5,0.7,1.0),t));}
  double diff=dot(N,L); if(diff<0)diff=0;
  V so=add(P,mul(N,0.001));
  if(sphit(so,L)>0.001)diff=0;
  double br=0.2+0.8*diff;
  V col;
  if(sph)col=v(1.0,0.2,0.2);
  else{int e=((int)floor(P.x)+(int)floor(P.z))&1; col=e?v(0.4,0.4,0.4):v(0.9,0.9,0.9);}
  return mul(col,br);
}

int main(void){
  int W=2400,H=1800,i,j;
  L=nrm(v(1,1,-1));
  double vh=2.0,vw=(double)W/H*2.0;
  V O=v(0,0,0),hz=v(vw,0,0),vt=v(0,vh,0);
  V ll=sub(sub(sub(O,mul(hz,0.5)),mul(vt,0.5)),v(0,0,1.0));
  FILE*f=fopen("reconstructed.ppm","w");
  fprintf(f,"P3\n%d %d\n255\n",W,H);
  for(j=0;j<H;j++)for(i=0;i<W;i++){
    double u=(double)i/(W-1),vv=(double)j/(H-1);
    V d=nrm(sub(add(add(ll,mul(hz,u)),mul(vt,1.0-vv)),O));
    V c=trace(O,d);
    int r=fmin(fmax(c.x,0.0),1.0)*255.99;
    int g=fmin(fmax(c.y,0.0),1.0)*255.99;
    int b=fmin(fmax(c.z,0.0),1.0)*255.99;
    fprintf(f,"%d %d %d\n",r,g,b);
  }
  fclose(f);
  return 0;
}
